                            <span className="font-bold text-slate-700 text-xs truncate max-w-[80px]">{a.partner_name || 'Unassigned'}</span>
                          </div>
                        </td>
                        <td className="px-6 py-6 text-right">
                          <div className="font-black text-slate-900 text-sm">{formatIndianCurrency(Number(a.fees ?? a.total_fees ?? 0), true, true)}</div>
                        </td>
                        <td className="px-6 py-6 text-right">
                          <div className="font-black text-emerald-600 text-sm">{formatIndianCurrency(Number(a.billed_amount || 0), true, true)}</div>
                        </td>
                        <td className="px-6 py-6 text-right">
                          <div className="font-black text-blue-600 text-sm">{formatIndianCurrency(Number(a.amount_receipt || 0), true, true)}</div>
                        </td>
                        <td className="px-6 py-6 text-center">
                          <span className="text-[10px] font-black text-slate-500 uppercase tracking-tighter bg-slate-100 px-2 py-1 rounded-md">
                            {(BILLING_CYCLE_LABELS[a.billing_cycle] || a.billing_cycle || 'ΓÇö').substring(0, 3)}
                          </span>
                        </td>
                        <td className="px-6 py-6 text-center">
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              setSelectedAssignment({ id: a.id, clientName: a.client_name || 'Unknown Client' });
                              setIsVaultModalOpen(true);
                            }}
                            className={cn(
                              "p-2 rounded-lg transition-all",
                              a.file_url 
                                ? "bg-emerald-50 text-emerald-600 border border-emerald-100 hover:bg-emerald-100" 
                                : "bg-slate-50 text-slate-400 border border-slate-200 hover:bg-blue-50 hover:text-blue-600"
                            )}
                            title={a.file_url ? "View in Vault" : "Upload to Vault"}
                          >
                            <Download size={14} strokeWidth={3} className={cn(a.file_url ? "" : "rotate-180")} />
                          </button>
                        </td>
                      </motion.tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </motion.div>
        ) : (
          <motion.div key="grid" initial={{ opacity: 0, scale: 0.98 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.98 }} transition={{ duration: 0.3 }}
            className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredAssignments.map((a, i) => (
              <motion.div key={a.id} initial={{ opacity: 0, y: 15 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.05 }}
                className="group relative rounded-[2rem] border border-slate-200 bg-white p-7 shadow-sm hover:shadow-[0_20px_40px_rgba(15,23,42,0.06)] transition-all hover:-translate-y-1 overflow-hidden"
              >
                 <div className="flex flex-col h-full gap-5">
                   <div>
                     <div className="text-[10px] font-black text-blue-500 uppercase tracking-[0.2em] mb-2 px-1">Engagement</div>
                     <Link href={`/assignments/${a.id}`}>
                       <h3 className="text-xl font-black text-slate-900 group-hover:text-blue-600 transition-colors leading-tight line-clamp-1">{a.client_name}</h3>
                     </Link>
                     <p className="text-sm font-bold text-slate-400 mt-2 leading-relaxed h-10 overflow-hidden text-ellipsis line-clamp-2">{a.scope_item || SUBCATEGORY_LABELS[a.subcategory] || a.subcategory || 'ΓÇö'}</p>
