'use client';

import { useState, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import { useProposalStore } from '@/store/proposalStore';
import { useClientStore } from '@/store/clientStore';
import { useUserStore } from '@/store/userStore';
import { useTemplateStore } from '@/store/templateStore';
import { useAuthStore } from '@/store/authStore';
import { Proposal, ProposalType, AssignmentType, FeeCategory } from '@/types';
import { 
  ArrowLeft, 
  Save, 
  Building2, 
  Briefcase, 
  IndianRupee, 
  ShieldCheck, 
  FileText, 
  Search,
  Sparkles,
  CheckCircle2,
  Plus,
  UserPlus,
  X,
  PlusCircle
} from 'lucide-react';
import Link from 'next/link';
import { toast } from 'react-hot-toast';
import { cn } from '@/lib/utils';

export default function NewProposalPage() {
  const router = useRouter();
  const { addProposal } = useProposalStore();
  const { clients } = useClientStore();
  const { partners } = useUserStore();
  const { templates } = useTemplateStore();
  const { user } = useAuthStore();

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [clientSearch, setClientSearch] = useState('');
  const [showClientResults, setShowClientResults] = useState(false);
  const [isSmartSuggesting, setIsSmartSuggesting] = useState(false);
  const [isAddingClient, setIsAddingClient] = useState(false);
  const [newClientData, setNewClientData] = useState({
    name: '',
    industry: 'Technology',
    spocName: '',
    spocEmail: '',
    spocPhone: '',
  });

  const { addClient } = useClientStore();

  const [formData, setFormData] = useState({
    client_id: '',
    client_name: '',
    quotation_amount: '',
    proposal_type: 'new' as ProposalType,
    assignment_type: 'internal_audit' as AssignmentType,
    fee_category: 'new' as FeeCategory,
    fiscal_year: '2025-26',
    responsible_partner: '',
    template_id: '',
    scope_areas: '',
    notes: '',
  });

  const filteredClients = useMemo(() => 
    clients.filter(c => 
      c.name.toLowerCase().includes(clientSearch.toLowerCase())
    ), [clients, clientSearch]
  );

  const handleSelectClient = (client: any) => {
    setFormData(prev => ({ ...prev, client_id: client.id, client_name: client.name }));
    setClientSearch(client.name);
    setShowClientResults(false);

    // Smart Auto-completion Logic
    setIsSmartSuggesting(true);
    setTimeout(() => {
      let suggestedType: AssignmentType = 'internal_audit';

      switch (client.industry?.toLowerCase()) {
        case 'technology':
          suggestedType = 'ifc';
          break;
        case 'logistics':
          suggestedType = 'forensic';
          break;
        case 'retail':
          suggestedType = 'mcs';
          break;
        default:
          suggestedType = 'internal_audit';
      }

      setFormData(prev => ({ ...prev, assignment_type: suggestedType }));
      setIsSmartSuggesting(false);
      toast.success(`Smart-suggested ${suggestedType.replace('_', ' ')} for ${client.industry} client`, {
        icon: 'Γ£¿',
        duration: 3000,
      });
    }, 600);
  };

  const handleQuickAddClient = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newClientData.name) {
      toast.error('Client name is required');
      return;
    }

    try {
      const addedClient = await addClient({
        ...newClientData,
        status: 'active',
      } as any);

      if (addedClient) {
        // Auto-select the new client with the REAL ID from backend
        setFormData(prev => ({ 
          ...prev, 
          client_id: addedClient.id, 
          client_name: addedClient.name 
        }));
        setClientSearch(addedClient.name);
        setIsAddingClient(false);

        // Reset new client form
        setNewClientData({
          name: '',
          industry: 'Technology',
          spocName: '',
          spocEmail: '',
          spocPhone: '',
        });

        toast.success(`${addedClient.name} added and selected!`, {
          icon: '≡ƒÅó',
        });
      }
    } catch (error) {
      toast.error('Failed to add client');
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.client_id) {
      toast.error('Please select a client');
      return;
    }
    setIsSubmitting(true);

