                                        />
                                    </div>

                                    <div className="space-y-1.5">
                                        <label className="text-[11px] font-bold text-slate-400 uppercase tracking-widest px-1">Priority</label>
                                        <select 
                                            value={priority}
                                            onChange={(e) => setPriority(e.target.value as TicketPriority)}
