'use client';

import { useState, useEffect, useCallback } from 'react';
import api from '@/lib/api';
import { Search, Loader2 } from 'lucide-react';
import { formatINR, cn } from '@/lib/utils';
import { format } from 'date-fns';

interface ProposalData {
    id: string;
    proposal_id: string;
    client_name: string;
    number: string;
    status: string;
    quotation_amount: number;
    amount?: number;
    date_sent?: string;
    created_at: string;
}

interface ProposalTabProps {
    managerId: string;
}

export function ProposalTab({ managerId }: ProposalTabProps) {
    const [data, setData] = useState<ProposalData[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [page, setPage] = useState(1);
    const [total, setTotal] = useState(0);

    const fetchData = useCallback(async () => {
        setLoading(true);
        try {
            const res = await api.get(`/api/managers/${managerId}/proposals`, {
                params: { search, page, limit: 10 }
            });
            setData(res.data.data);
            setTotal(res.data.total);
        } catch (err) {
            console.error('Failed to fetch proposals:', err);
        } finally {
            setLoading(false);
        }
    }, [managerId, search, page]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    return (
        <div className="space-y-4">
            <div className="relative max-w-sm group">
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" />
                <input 
                    type="text"
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    placeholder="Search proposals..."
                    className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm font-medium focus:ring-2 focus:ring-[var(--brand-navy)]/10 outline-none transition-all"
                />
            </div>

            <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-[var(--navy-50)]/50 border-b border-slate-200">
                                <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-wider font-accent">Proposal ID</th>
                                <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-wider font-accent">Client Name</th>
                                <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-wider font-accent">Date Sent</th>
                                <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-wider font-accent">Status</th>
                                <th className="px-6 py-4 text-[11px] font-black text-slate-400 uppercase tracking-wider text-right font-accent">Amount</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {loading ? (
                                <tr>
                                    <td colSpan={5} className="px-6 py-20 text-center">
                                        <div className="flex flex-col items-center gap-3">
                                            <Loader2 size={32} className="text-[var(--brand-navy)] animate-spin" />
                                            <p className="text-sm font-bold text-slate-500 uppercase tracking-widest font-accent">Loading Proposals</p>
                                        </div>
                                    </td>
                                </tr>
                            ) : data.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="px-6 py-20 text-center text-slate-500 font-medium">
                                        No proposals found.
                                    </td>
                                </tr>
                            ) : data.map((proposal) => (
                                <tr key={proposal.id} className="hover:bg-slate-50/80 transition-colors group">
                                    <td className="px-6 py-4">
                                        <div className="font-bold text-slate-900 group-hover:text-[var(--brand-navy)] transition-colors">#{proposal.proposal_id}</div>
                                    </td>
                                    <td className="px-6 py-4 text-sm font-bold text-slate-700">
                                        {proposal.client_name}
                                    </td>
                                    <td className="px-6 py-4 text-sm font-medium text-slate-600">
                                        {proposal.date_sent ? format(new Date(proposal.date_sent), 'dd MMM yyyy') : 'N/A'}
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className={cn(
                                            "inline-flex items-center px-2.5 py-1 rounded-full text-[11px] font-bold uppercase tracking-wider",
                                            proposal.status === 'won' ? "bg-emerald-50 text-emerald-700 border border-emerald-100" : 
                                            proposal.status === 'lost' ? "bg-rose-50 text-rose-700 border border-rose-100" :
                                            "bg-amber-50 text-amber-700 border border-amber-100"
                                        )}>
                                            {proposal.status}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-right font-black text-slate-900">
                                        {formatINR(proposal.amount ?? proposal.quotation_amount)}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Plus } from 'lucide-react';
import { useAssignmentStore } from '@/store/assignmentStore';
import { CATEGORY_LABELS, SUBCATEGORY_LABELS, AssignmentCategory, AssignmentSubcategory, BillingCycle, User } from '@/types';
import api from '@/lib/api';

interface AddAssignmentModalProps {
  open: boolean;
  setOpen: (open: boolean) => void;
}

interface ClientOption {
  id: string;
  name: string;
}

interface FormData {
  client_id: string;
  gstn: string;
  partner_id: string;
  manager_id: string;
  category: AssignmentCategory;
  subcategory: AssignmentSubcategory;
  total_fees: number;
  billing_cycle: BillingCycle;
  fiscal_year: string;
  scope_item: string;
  scope_areas: string;
}

export default function AddAssignmentModal({ open, setOpen }: AddAssignmentModalProps) {
  const { addAssignment } = useAssignmentStore();
  const [clients, setClients] = useState<ClientOption[]>([]);
  const [partners, setPartners] = useState<User[]>([]);
  const [managers, setManagers] = useState<User[]>([]);
  const [form, setForm] = useState<FormData>({
    client_id: '',
    gstn: '',
    partner_id: '',
    manager_id: '',
    category: 'A',
    subcategory: 'statutory_audit',
    total_fees: 0,
    billing_cycle: 'monthly',
    fiscal_year: '2025-26',
    scope_item: '',
    scope_areas: ''
  });

  useEffect(() => {
    if (open) {
      api.get('/api/clients').then(res => {
        setClients(res.data.map((c: ClientOption) => ({ id: c.id, name: c.name })));
      }).catch(() => setClients([]));

      api.get('/api/users/partners').then(res => {
        setPartners(res.data || []);
      }).catch(() => setPartners([]));

      api.get('/api/users/managers').then(res => {
        setManagers(res.data || []);
      }).catch(() => setManagers([]));
    }
  }, [open]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const sanitizeUUID = (val: string) => (val && val.includes('-')) ? val : undefined;

    const payload = {
      ...form,
      partner_id: sanitizeUUID(form.partner_id),
      manager_id: sanitizeUUID(form.manager_id)
    };
    await addAssignment(payload);
    setOpen(false);
    setForm({
      client_id: '',
      gstn: '',
      partner_id: '',
      manager_id: '',
      category: 'A',
      subcategory: 'statutory_audit',
      total_fees: 0,
      billing_cycle: 'monthly',
      fiscal_year: '2025-26',
      scope_item: '',
      scope_areas: ''
    });
  };

  return (
    <AnimatePresence>
      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={() => setOpen(false)}
            className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
          />

          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            className="relative w-full max-w-lg bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden"
          >
            {/* Header */}
            <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between bg-gradient-to-r from-slate-50 to-white">
              <div>
                <h2 className="text-xl font-bold text-slate-900 tracking-tight">Add New Assignment</h2>
                <p className="text-xs text-slate-500 mt-0.5 font-medium">Create a new client engagement</p>
              </div>
              <button
                onClick={() => setOpen(false)}
                className="w-10 h-10 flex items-center justify-center rounded-2xl hover:bg-rose-50 text-slate-400 hover:text-rose-500 transition-all border border-transparent hover:border-rose-100"
              >
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-5">
              <div className="space-y-4">
                {/* Client Selection */}
                <div className="space-y-1.5">
                  <label className="text-[11px] font-bold text-slate-400 uppercase tracking-widest px-1">Client</label>
                  <select
                    required
                    value={form.client_id}
                    onChange={(e) => setForm({ ...form, client_id: e.target.value })}
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-slate-50/50 text-sm font-medium focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 focus:bg-white transition-all cursor-pointer appearance-none"
                  >
                    <option value="">Select a client</option>
                    {clients.map(c => (
                      <option key={c.id} value={c.id}>{c.name}</option>
                    ))}
                  </select>
                </div>

                {/* GSTN */}
                <div className="space-y-1.5">
