'use client';

import React, { useState, useEffect, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Save, FileText, CheckCircle2, XCircle, Clock } from 'lucide-react';
import { useProposalStore } from '@/store/proposalStore';
import { useUserStore } from '@/store/userStore';
import { ASSIGNMENT_TYPE_LABELS, Proposal, ProposalType, AssignmentType, ProposalStatus } from '@/types';
import api from '@/lib/api';

interface EditProposalModalProps {
  open: boolean;
  setOpen: (open: boolean) => void;
  proposal: Proposal;
}

interface ClientOption {
  id: string;
  name: string;
}

interface FormData {
  client_id: string;
  proposal_type: ProposalType;
  assignment_type: AssignmentType;
  quotation_amount: number;
  status: ProposalStatus;
  fiscal_year: string;
  responsible_partner: string;
  notes: string;
}

export default function EditProposalModal({ open, setOpen, proposal }: EditProposalModalProps) {
  const { updateProposal } = useProposalStore();
  const { partners } = useUserStore();
  const [clients, setClients] = useState<ClientOption[]>([]);
  const [form, setForm] = useState<FormData>({
    client_id: '',
    proposal_type: 'new',
    assignment_type: 'internal_audit',
    quotation_amount: 0,
    status: 'pending',
    fiscal_year: '2025-26',
    responsible_partner: '',
    notes: ''
  });

  useEffect(() => {
    if (open) {
      api.get('/api/clients').then(res => {
        setClients(res.data.map((c: ClientOption) => ({ id: c.id, name: c.name })));
      }).catch(() => setClients([]));
    }
  }, [open]);

  const initialForm = useMemo(() => ({
    client_id: proposal?.client_id || '',
    proposal_type: proposal?.proposal_type || 'new',
    assignment_type: proposal?.assignment_type || 'internal_audit',
    quotation_amount: proposal?.quotation_amount || 0,
    status: proposal?.status || 'pending',
    fiscal_year: proposal?.fiscal_year || '2025-26',
    responsible_partner: proposal?.responsible_partner || '',
    notes: proposal?.notes || ''
  }), [proposal]);

  useEffect(() => {
    if (open && proposal) {
      setForm(initialForm);
    }
  }, [initialForm, open, proposal]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const backendProposalType = form.proposal_type === 'renewal' ? 'revision' : 'new';
    await updateProposal(proposal.id, {
      client_id: form.client_id,
      proposal_type: backendProposalType as ProposalType,
      assignment_type: form.assignment_type,
      quotation_amount: form.quotation_amount,
      status: form.status,
      fiscal_year: form.fiscal_year,
      responsible_partner: form.responsible_partner,
      notes: form.notes
    });
    setOpen(false);
  };

  return (
    <AnimatePresence>
      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={() => setOpen(false)}
            className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
          />

          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            className="relative w-full max-w-lg bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden"
          >
            {/* Header */}
            <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between bg-gradient-to-r from-slate-50 to-white">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-2xl bg-blue-500/10 flex items-center justify-center">
                  <FileText className="text-blue-600" size={20} />
                </div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900 tracking-tight">Edit Proposal</h2>
                  <p className="text-xs text-slate-500 mt-0.5 font-medium">{proposal.number}</p>
                </div>
              </div>
              <button
                onClick={() => setOpen(false)}
                className="w-10 h-10 flex items-center justify-center rounded-2xl hover:bg-rose-50 text-slate-400 hover:text-rose-500 transition-all border border-transparent hover:border-rose-100"
              >
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-5">
              <div className="space-y-4">
                {/* Client Selection */}
                <div className="space-y-1.5">
                  <label className="text-[11px] font-bold text-slate-400 uppercase tracking-widest px-1">Client</label>
                  <select
                    required
                    value={form.client_id}
                    onChange={(e) => setForm({ ...form, client_id: e.target.value })}
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-slate-50/50 text-sm font-medium focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 focus:bg-white transition-all cursor-pointer appearance-none"
                  >
                    <option value="">Select a client</option>
                    {clients.map(c => (
                      <option key={c.id} value={c.id}>{c.name}</option>
                    ))}
                  </select>
                </div>

                {/* Status Selection */}
                <div className="space-y-1.5">
                  <label className="text-[11px] font-bold text-slate-400 uppercase tracking-widest px-1">Status</label>
                  <div className="grid grid-cols-3 gap-2">
                    {(['pending', 'won', 'lost'] as ProposalStatus[]).map((s) => (
                      <button
                        key={s}
                        type="button"
                        onClick={() => setForm({ ...form, status: s })}
                        className={`flex items-center justify-center gap-1.5 py-2.5 rounded-xl text-xs font-bold border transition-all ${
                          form.status === s
                            ? s === 'won'
                              ? 'bg-emerald-500 border-emerald-500 text-white shadow-lg shadow-emerald-500/25'
                              : s === 'lost'
                              ? 'bg-rose-500 border-rose-500 text-white shadow-lg shadow-rose-500/25'
                              : 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-600/25'
                            : 'bg-slate-50 border-slate-200 text-slate-500 hover:bg-slate-100'
                        }`}
                      >
                        {s === 'won' && <CheckCircle2 size={12} />}
                        {s === 'lost' && <XCircle size={12} />}
                        {s === 'pending' && <Clock size={12} />}
                        {s.charAt(0).toUpperCase() + s.slice(1)}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  {/* Proposal Type */}
                  <div className="space-y-1.5">
                    <label className="text-[11px] font-bold text-slate-400 uppercase tracking-widest px-1">Proposal Type</label>
                    <select
                      value={form.proposal_type}
                      onChange={(e) => setForm({ ...form, proposal_type: e.target.value as ProposalType })}
                      className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-slate-50/50 text-sm font-semibold focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 focus:bg-white transition-all cursor-pointer appearance-none"
                    >
                      <option value="new">New Proposal</option>
                      <option value="revision">Renewal</option>
                    </select>
                  </div>

                  {/* Assignment Type */}
                  <div className="space-y-1.5">
                    <label className="text-[11px] font-bold text-slate-400 uppercase tracking-widest px-1">Assignment Type</label>
                    <select
                      value={form.assignment_type}
                      onChange={(e) => setForm({ ...form, assignment_type: e.target.value as AssignmentType })}
                      className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-slate-50/50 text-sm font-semibold focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 focus:bg-white transition-all cursor-pointer appearance-none"
                    >
                      {Object.entries(ASSIGNMENT_TYPE_LABELS).map(([key, label]) => (
                        <option key={key} value={key}>{label}</option>
                      ))}
                    </select>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  {/* Quotation Amount */}
                  <div className="space-y-1.5">
                    <label className="text-[11px] font-bold text-slate-400 uppercase tracking-widest px-1">Quotation Amount (Γé╣)</label>
                    <div className="relative">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">Γé╣</span>
                      <input
                        type="number"
                        required
                        value={form.quotation_amount || ''}
                        onChange={(e) => setForm({ ...form, quotation_amount: Number(e.target.value) })}
                        className="w-full pl-8 pr-4 py-3 rounded-2xl border border-slate-200 bg-slate-50/50 text-sm font-bold focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 focus:bg-white transition-all"
                      />
                    </div>
                  </div>

                  {/* Fiscal Year */}
                  <div className="space-y-1.5">
                    <label className="text-[11px] font-bold text-slate-400 uppercase tracking-widest px-1">Fiscal Year</label>
                    <select
                      value={form.fiscal_year}
                      onChange={(e) => setForm({ ...form, fiscal_year: e.target.value })}
                      className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-slate-50/50 text-sm font-semibold focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 focus:bg-white transition-all cursor-pointer appearance-none"
                    >
                      <option value="2024-25">2024-25</option>
                      <option value="2025-26">2025-26</option>
                      <option value="2026-27">2026-27</option>
                    </select>
                  </div>
                </div>

                {/* Responsible Partner */}
                <div className="space-y-1.5">
                  <label className="text-[11px] font-bold text-slate-400 uppercase tracking-widest px-1">Responsible Partner</label>
                  <select
                    required
                    value={form.responsible_partner}
                    onChange={(e) => setForm({ ...form, responsible_partner: e.target.value })}
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-slate-50/50 text-sm font-medium focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 focus:bg-white transition-all cursor-pointer appearance-none"
                  >
                    <option value="">Select a partner</option>
                    {partners.map(p => (
                      <option key={p.id} value={p.id}>{p.full_name}</option>
                    ))}
                  </select>
                </div>

                {/* Notes */}
                <div className="space-y-1.5">
                  <label className="text-[11px] font-bold text-slate-400 uppercase tracking-widest px-1">Internal Notes</label>
                  <textarea
                    value={form.notes}
                    onChange={(e) => setForm({ ...form, notes: e.target.value })}
                    rows={2}
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 bg-slate-50/50 text-sm font-medium focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 focus:bg-white transition-all placeholder:text-slate-300 resize-none"
                  />
                </div>
              </div>

              {/* Action Buttons */}
              <div className="flex gap-3 pt-4">
                <button
                  type="button"
                  onClick={() => setOpen(false)}
                  className="flex-1 px-6 py-3.5 rounded-2xl border border-slate-200 text-sm font-bold text-slate-600 hover:bg-slate-50 transition-all active:scale-95"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="flex-1 px-6 py-3.5 rounded-2xl bg-gradient-to-r from-blue-600 to-indigo-600 text-white text-sm font-bold shadow-[0_8px_20px_rgba(37,99,235,0.25)] hover:shadow-[0_12px_28px_rgba(37,99,235,0.35)] hover:-translate-y-0.5 transition-all active:scale-95 flex items-center justify-center gap-2"
                >
                  <Save size={18} />
                  Update Proposal
                </button>
              </div>
            </form>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { X, UserCheck, Save, Shield, User as UserIcon, Users } from 'lucide-react';
import api from '@/lib/api';
import toast from 'react-hot-toast';
import { useAuthStore } from '@/store/authStore';
import type { User, UserRole } from '@/types';

interface EditUserModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  user: User | null;
}

const ROLES: { value: UserRole; label: string; description: string }[] = [
  { value: 'partner', label: 'Partner', description: 'Full access to client and user management' },
  { value: 'director', label: 'Director', description: 'Can review and approve proposals' },
  { value: 'manager', label: 'Manager', description: 'Can manage assignments and billing' },
  { value: 'assistant_manager', label: 'Asst. Manager', description: 'Assists with operational management' },
  { value: 'sr_executive', label: 'Sr. Executive', description: 'Senior level operations and reporting' },
  { value: 'executive', label: 'Executive', description: 'General operations and execution' },
  { value: 'staff', label: 'Staff', description: 'Standard platform access' },
  { value: 'analyst', label: 'Analyst', description: 'Data analysis and research' },
  { value: 'admin', label: 'Administrator', description: 'System-wide configuration and security' },
];

export default function EditUserModal({ isOpen, onClose, onSuccess, user }: EditUserModalProps) {
  const [formData, setFormData] = useState({
    full_name: '',
    display_name: '',
    role: 'staff' as UserRole,
    reports_to: '',
    is_active: true
  });
  const [supervisors, setSupervisors] = useState<User[]>([]);
  const [loading, setLoading] = useState(false);
  const { user: currentUser } = useAuthStore();
  const isAdmin = currentUser?.role === 'admin';

  useEffect(() => {
    if (isOpen && user) {
      setFormData({
        full_name: user.full_name,
        display_name: user.display_name || '',
        role: user.role,
        reports_to: user.reports_to || '',
        is_active: user.is_active !== false
      });
      fetchSupervisors();
    }
  }, [isOpen, user]);

  const fetchSupervisors = async () => {
    try {
      const res = await api.get('/api/users');
      // Filter for users who can be supervisors
      const potentialSupervisors = res.data.filter((u: User) =>
        (u.role === 'partner' || u.role === 'director' || u.role === 'manager') && u.id !== user?.id
      );
      setSupervisors(potentialSupervisors);
    } catch (err) {
      console.error('Error fetching supervisors:', err);
    }
  };

  if (!isOpen || !user) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.full_name.trim()) {
      toast.error('Full Name is required');
      return;
    }

    setLoading(true);
    try {
      await api.patch(`/api/users/${user.id}`, {
        ...formData,
        display_name: formData.display_name.trim() || formData.full_name.trim(),
        reports_to: formData.reports_to || null
      });
      toast.success('User updated successfully');
      onSuccess();
      onClose();
    } catch (err: any) {
      console.error('Error updating user:', err);
      toast.error(err.response?.data?.error || 'Failed to update user');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/20 backdrop-blur-sm">
      <div className="bg-white border border-slate-200 rounded-2xl w-full max-w-2xl overflow-hidden animate-in fade-in zoom-in duration-200 shadow-2xl">
        <div className="px-6 py-4 border-b border-slate-200 flex items-center justify-between bg-slate-50">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-indigo-100 border border-indigo-200 flex items-center justify-center">
              <UserCheck className="w-4 h-4 text-indigo-600" />
            </div>
            <h2 className="text-lg font-bold text-slate-900">Edit User</h2>
          </div>
          <button
            onClick={onClose}
            className="p-2 hover:bg-slate-200 rounded-lg text-slate-500 transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto max-h-[85vh]">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="label">
                <div className="flex items-center gap-2">
                  <UserIcon className="w-3 h-3" />
                  Full Name *
                </div>
              </label>
              <input
                type="text"
                required
                className="input text-sm"
                placeholder="John Doe"
                value={formData.full_name}
                onChange={(e) => setFormData({ ...formData, full_name: e.target.value })}
              />
            </div>

            <div className="space-y-1">
              <label className="label">
                <div className="flex items-center gap-2">
                  <UserIcon className="w-3 h-3" />
                  Display Name
                </div>
              </label>
              <input
                type="text"
                className="input text-sm"
                placeholder="John D."
                value={formData.display_name}
                onChange={(e) => setFormData({ ...formData, display_name: e.target.value })}
              />
            </div>
          </div>

          <div className="space-y-1">
            <label className="label">
              <div className="flex items-center gap-2">
                <Users className="w-3 h-3" />
                Reporting To (Supervisor)
              </div>
            </label>
            <select
              className={`select text-sm h-[42px] ${!isAdmin ? 'bg-slate-50 cursor-not-allowed opacity-75' : ''}`}
              value={formData.reports_to}
              onChange={(e) => setFormData({ ...formData, reports_to: e.target.value })}
              disabled={!isAdmin}
            >
              <option value="">No Supervisor (Direct Admin)</option>
              {supervisors.map((s) => (
                <option key={s.id} value={s.id}>
                  {s.full_name} ({s.role.split('_').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ')})
                </option>
              ))}
            </select>
          </div>

          <div className="space-y-2">
            <label className="label">
              <div className="flex items-center gap-2">
                <Shield className="w-3 h-3" />
                Security Role
              </div>
            </label>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
              {ROLES.map((role) => (
                <button
                  key={role.value}
                  type="button"
                  onClick={() => setFormData({ ...formData, role: role.value })}
                  className={`flex flex-col items-start p-3 rounded-xl border transition-all text-left group ${
                    formData.role === role.value
                      ? 'bg-indigo-50 border-indigo-300 ring-1 ring-indigo-300'
                      : 'bg-white border-slate-200 hover:border-slate-300 hover:bg-slate-50'
                  }`}
                >
                  <span className={`text-[13px] font-bold ${
                    formData.role === role.value ? 'text-indigo-700' : 'text-slate-900 group-hover:text-indigo-600'
                  }`}>
                    {role.label}
                  </span>
                  <span className="text-[11px] text-slate-500 mt-0.5 line-clamp-1 leading-tight">
                    {role.description}
                  </span>
                </button>
              ))}
            </div>
          </div>

          <div className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl border border-slate-200">
            <input
              type="checkbox"
              id="is_active"
              className="w-4 h-4 text-indigo-600 border-slate-300 rounded focus:ring-indigo-500"
              checked={formData.is_active}
              onChange={(e) => setFormData({ ...formData, is_active: e.target.checked })}
            />
            <label htmlFor="is_active" className="text-sm font-medium text-slate-700">
              Account is active and can login
            </label>
          </div>

          <div className="pt-2 flex gap-3">
            <button
              type="button"
              onClick={onClose}
              className="btn btn-secondary flex-1 justify-center h-11"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              className="btn btn-primary bg-indigo-600 hover:bg-indigo-700 text-white flex-1 justify-center h-11"
            >
              {loading ? (
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <>
                  <Save className="w-4 h-4" />
                  <span>Save Changes</span>
                </>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { X, Upload, Link as LinkIcon, FileText, CheckCircle2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import api from '@/lib/api';
import toast from 'react-hot-toast';

interface VaultUploadModalProps {
  isOpen: boolean;
  onClose: () => void;
  assignmentId: string;
  clientName: string;
  onSuccess?: () => void;
}

export default function VaultUploadModal({ isOpen, onClose, assignmentId, clientName, onSuccess }: VaultUploadModalProps) {
  const [fileUrl, setFileUrl] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!fileUrl) return;

    try {
      setIsSubmitting(true);
      await api.patch(`/api/assignments/${assignmentId}/vault`, { file_url: fileUrl });
      setIsSuccess(true);
      toast.success('Document uploaded to vault');
      setTimeout(() => {
        onClose();
        if (onSuccess) onSuccess();
        // Reset state after closing
        setTimeout(() => {
          setIsSuccess(false);
          setFileUrl('');
        }, 300);
      }, 1500);
    } catch (err: any) {
      console.error('Vault upload error:', err);
      toast.error(err.response?.data?.error || 'Failed to upload document');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            className="relative w-full max-w-lg bg-white rounded-[2.5rem] shadow-2xl overflow-hidden"
          >
            {/* Header */}
            <div className="bg-slate-50 px-8 py-6 flex items-center justify-between border-b border-slate-100">
              <div>
                <h3 className="text-xl font-black text-slate-900">Upload Working Paper</h3>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">{clientName}</p>
              </div>
              <button onClick={onClose} className="p-2 rounded-xl hover:bg-slate-200 text-slate-400 transition-colors">
                <X size={20} strokeWidth={3} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8">
              {isSuccess ? (
                <div className="py-12 flex flex-col items-center text-center">
                  <div className="w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center text-emerald-500 mb-6 border-4 border-emerald-100">
                    <CheckCircle2 size={40} />
                  </div>
                  <h4 className="text-2xl font-black text-slate-900 mb-2">Vault Updated!</h4>
                  <p className="text-slate-500 font-medium">The document link has been securely saved to the assignment vault.</p>
                </div>
              ) : (
                <div className="space-y-6">
                  <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100 flex items-start gap-4">
                    <div className="p-2 bg-white rounded-lg text-blue-600 shadow-sm">
                      <FileText size={18} />
                    </div>
                    <p className="text-xs font-bold text-blue-700 leading-relaxed">
                      Enter the secure link to your working paper (Google Drive, SharePoint, etc.). 
                      This document will be accessible in the firm's Document Vault.
                    </p>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-1">Secure Document URL</label>
                    <div className="relative group">
                      <LinkIcon size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 transition-colors" />
                      <input
                        autoFocus
                        required
                        type="url"
                        placeholder="https://drive.google.com/..."
                        value={fileUrl}
                        onChange={(e) => setFileUrl(e.target.value)}
                        className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 bg-slate-50 text-sm font-bold text-slate-900 focus:outline-none focus:ring-4 focus:ring-blue-600/5 focus:border-blue-600 focus:bg-white transition-all shadow-inner-sm"
                      />
                    </div>
                  </div>

                  <div className="pt-4 flex gap-3">
                    <button
                      type="button"
                      onClick={onClose}
                      className="flex-1 py-4 rounded-2xl border border-slate-200 text-sm font-black text-slate-400 hover:bg-slate-50 transition-all"
                    >
                      Cancel
                    </button>
                    <button
                      type="submit"
                      disabled={isSubmitting || !fileUrl}
                      className="flex-[2] py-4 rounded-2xl bg-slate-900 text-white text-sm font-black flex items-center justify-center gap-2 hover:bg-slate-800 transition-all shadow-xl shadow-slate-200 disabled:opacity-50 disabled:shadow-none"
                    >
                      {isSubmitting ? (
                        <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                      ) : (
                        <>
                          <Upload size={18} strokeWidth={3} />
                          Secure to Vault
                        </>
                      )}
                    </button>
                  </div>
                </div>
              )}
            </form>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}

'use client';

import React, { useState } from 'react';
import { Download } from 'lucide-react';
import toast from 'react-hot-toast';
import { Proposal } from '@/types';

import api from '@/lib/api';

interface ProposalDownloadButtonProps {
  proposal: Proposal;
  variant?: 'icon' | 'full';
  className?: string;
}

export function ProposalDownloadButton({ proposal, variant = 'icon', className }: ProposalDownloadButtonProps) {
  const [isDownloading, setIsDownloading] = useState(false);

  const handleDownload = async (e: React.MouseEvent) => {
    e.stopPropagation();
    const toastId = toast.loading('Downloading proposal PDF...');
    setIsDownloading(true);
    try {
      const response = await api.get(`/api/proposals/${proposal.id}/export/pdf`, {
        responseType: 'blob',
      });
      
      const blob = new Blob([response.data], { type: 'application/pdf' });
      const fileName = `Proposal_${proposal.number?.replace(/\//g, '_') || proposal.id}.pdf`;
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = fileName;
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
      toast.success('Proposal downloaded successfully', { id: toastId });
    } catch (error: any) {
      console.error('PDF Download Error:', error);
      toast.error(error.message || 'Failed to download PDF', { id: toastId });
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <button
      className={className}
      onClick={handleDownload}
      disabled={isDownloading}
      title="Download Proposal PDF"
    >
      {isDownloading ? (
        <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin mx-auto" />
      ) : (
        variant === 'icon' ? <Download /> : 'Download Proposal PDF'
      )}
    </button>
  );
}

import { type ClassValue, clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

interface ValidationDetail {
  field?: string;
  message?: string;
  msg?: string;
}

interface ErrorResponse {
  response?: {
    data?: {
      error?: {
        message?: string;
        details?: unknown[] | string;
      };
      message?: string;
      details?: unknown[] | string;
    };
  };
  message?: string;
}

/**
 * Merges Tailwind classes with clsx logic.
 * Essential for premium components to handle dynamic styling safely.
 */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

/**
 * Formats a number to Indian currency format (Lakhs, Crores).
 */
export function formatIndianCurrency(amount: number | string, includeSymbol = true, _short = false) {
  const numAmount = Number(amount || 0);
  const formatter = new Intl.NumberFormat('en-IN', {
    style: includeSymbol ? 'currency' : 'decimal',
    currency: 'INR',
    maximumFractionDigits: 0,
  });
  return formatter.format(numAmount);
}

/**
 * Specialized INR formatter with suffix (K, L, Cr)
 */
export function formatINR(amount: number) {
  return 'Γé╣' + amount.toLocaleString('en-IN');
}

/**
 * Safely extracts a string error message from various error types,
 * especially handling Axios errors and nested object responses from the backend.
 */
export function getErrorMessage(err: ErrorResponse | string | unknown): string {
  if (!err) return 'An unknown error occurred';

  // Handle string errors
  if (typeof err === 'string') return err;

  // Handle Axios response errors
  if (typeof err === 'object' && err !== null && 'response' in err) {
    const responseErr = err as ErrorResponse;
    if (responseErr.response?.data) {
      const data = responseErr.response.data;

      // Check for nested error object (e.g., { error: { message: "...", code: "...", details: [...] } })
      if (data.error && typeof data.error === 'object') {
        const e = data.error as { message?: string; details?: unknown[] | string };
        // If there are specific validation details, join them
        if (Array.isArray(e.details) && e.details.length > 0) {
          return e.details.map((d) => {
            if (typeof d === 'object' && d !== null) {
              const detail = d as ValidationDetail;
              return detail.field ? `${detail.field}: ${detail.message || 'Invalid value'}` : (detail.message || 'Invalid value');
            }
            return String(d);
          }).join(', ');
        }
        return e.message || (typeof e.details === 'string' ? e.details : JSON.stringify(e));
      }

      // Check for direct fields
      if (Array.isArray(data.details) && data.details.length > 0) {
        return data.details.map((d) => {
          if (typeof d === 'object' && d !== null) {
            const detail = d as ValidationDetail;
            return detail.field ? `${detail.field}: ${detail.message || detail.msg || 'Invalid value'}` : (detail.message || detail.msg || 'Invalid value');
          }
          return String(d);
        }).join(', ');
      }

      const errVal = data.error || data.message;
      if (typeof errVal === 'string') return errVal;
      if (data.details) {
        return typeof data.details === 'string' ? data.details : JSON.stringify(data.details);
      }
      return typeof data === 'string' ? data : 'Server error';
    }
  }

  // Handle standard Error objects
  if (err instanceof Error) return err.message;

  // Handle other object types
  if (typeof err === 'object' && err !== null && 'message' in err) {
    return String(err.message);
  }

  try {
    return JSON.stringify(err);
  } catch {
    return String(err);
  }
}

import { create } from 'zustand';
import { Assignment } from '@/types';
import api from '@/lib/api';
import { toast } from 'react-hot-toast';
import { getErrorMessage } from '@/lib/utils';

interface AssignmentStore {
  assignments: Assignment[];
  isLoading: boolean;
  error: string | null;
  fetchAssignments: () => Promise<void>;
  fetchAssignmentById: (id: string) => Promise<Assignment | null>;
  addAssignment: (assignment: Partial<Assignment>) => Promise<void>;
  updateAssignment: (id: string, updates: Partial<Assignment>) => Promise<void>;
}

export const useAssignmentStore = create<AssignmentStore>((set, get) => ({
  assignments: [],
  isLoading: false,
  error: null,

  fetchAssignments: async () => {
    set({ isLoading: true, error: null });
    try {
      const response = await api.get('/api/assignments');
      set({ assignments: response.data, isLoading: false });
    } catch (err: unknown) {
      const message = getErrorMessage(err);
      set({ error: message, isLoading: false });
      toast.error(message);
    }
  },

  fetchAssignmentById: async (id) => {
    set({ isLoading: true, error: null });
    try {
      const response = await api.get(`/api/assignments/${id}`);
      set({ isLoading: false });
      return response.data;
    } catch (err: unknown) {
      const message = getErrorMessage(err);
      set({ error: message, isLoading: false });
      toast.error(message);
      return null;
    }
  },

  addAssignment: async (assignment) => {
    set({ isLoading: true, error: null });
    try {
      const response = await api.post('/api/assignments', assignment);
      set((state) => ({
        assignments: [response.data, ...state.assignments],
        isLoading: false
      }));
      toast.success('Assignment created successfully');
    } catch (err: unknown) {
      const message = getErrorMessage(err);
      set({ error: message, isLoading: false });
      toast.error(message);
    }
  },

  updateAssignment: async (id, updates) => {
    set({ isLoading: true, error: null });
    try {
      const response = await api.put(`/api/assignments/${id}`, updates);
      set((state) => ({
        assignments: state.assignments.map((a) => (a.id === id ? response.data : a)),
        isLoading: false
      }));
      toast.success('Assignment updated successfully');
    } catch (err: unknown) {
      const message = getErrorMessage(err);
      set({ error: message, isLoading: false });
      toast.error(message);
    }
  },
}));

